sql:
SELECT instrument_name 
FROM instruments 
WHERE instrument_id NOT IN (
    SELECT instrument_id 
    FROM market_data
);

SELECT i.exchange, COUNT(DISTINCT i.instrument_id) AS unique_instruments_traded
FROM instruments i
GROUP BY i.exchange;

SELECT DISTINCT users.user_id, users.user_name, users.email
FROM alerts
JOIN users ON alerts.user_id = users.user_id;

external_knowledge:
Keeping an eye on price movements refers to having active alerts set for price levels; traders are users with the role 'trader'.;
Financial instruments are stocks, bonds, or commodities being tracked for price changes.;
Active alerts mean the status of the alert is 'active'.;

sql:
SELECT role_name, description
FROM roles
WHERE role_id <= 5;

SELECT DISTINCT i.instrument_id, i.instrument_name, i.type, i.exchange, i.isin, i.sector, i.issue_date, i.maturity_date
FROM instruments AS i
JOIN market_data AS md ON i.instrument_id = md.instrument_id;

SELECT i.*, a.* 
FROM instruments i
LEFT JOIN alerts a ON i.instrument_id = a.instrument_id;
